INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8e71ba1d-a3b1-4e4b-b6d7-7ca151dcc0f3',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vue Forms — Controlled vs Uncontrolled, and the VeeValidate + Zod Pattern$escape$,
  $escape$Vue's `v-model` makes controlled forms the default — every input binds to a reactive `ref`, giving real-time access to form state. Uncontrolled forms use `useTemplateRef()` to read DOM values only on submit — useful for file inputs or third-party widgets that own their own state.

For production forms, Vue's ecosystem answer to React Hook Form + Zod is VeeValidate with `@vee-validate/zod`. The `toTypedSchema()` adapter converts a Zod schema into VeeValidate's validation format, preserving TypeScript inference end-to-end. `useForm()` returns `handleSubmit`, `defineField`, and `errors` — `defineField` produces a `[modelValue, attrs]` tuple you spread onto `<input>` elements, keeping templates declarative.

Unlike RHF's `register()`, `defineField` uses Vue's two-way binding model, generating both a reactive ref and the `onUpdate:modelValue` handler automatically. Validation runs on blur by default; set `validateOnModelUpdate: true` in `useForm` config for eager per-keystroke feedback. No render-prop wrappers, no Controller components — just reactive state wired directly to a Zod schema with full type inference on the `handleSubmit` callback.$escape$,
  $escape$import { useForm } from 'vee-validate'
import { toTypedSchema } from '@vee-validate/zod'
import { z } from 'zod'

const schema = toTypedSchema(z.object({
  email: z.string().email(),
  password: z.string().min(8),
}))

const { handleSubmit, defineField, errors } = useForm({ validationSchema: schema })
const [email, emailAttrs] = defineField('email')
const [password, passwordAttrs] = defineField('password')

const onSubmit = handleSubmit((values) => {
  // values is fully typed: { email: string; password: string }
  console.log(values)
})$escape$,
  $escape$typescript$escape$,
