INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f736f3ce-2978-44e5-8f3b-df8d35b0d759',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vue i18n Done Right — vue-i18n, Never Hardcoded Strings$escape$,
  $escape$Hardcoded strings in Vue components are a maintenance trap. Use `vue-i18n` v9+ with the Composition API: call `useI18n()` to get `t()` and `locale` inside `<script setup>`. Define messages per locale in flat or nested JSON, then reference keys via `t('nav.home')` in templates — never raw strings.

For dates and numbers, skip moment.js entirely. Vue-i18n exposes `d()` and `n()` which delegate to the native `Intl.DateTimeFormat` and `Intl.NumberFormat` APIs. Pass a named format key configured in `datetimeFormats` or `numberFormats` on your `createI18n` instance. Locale switching is reactive — binding `locale.value = 'fr'` triggers re-renders across all consuming components automatically.

For async locale loading, lazy-load message files with `setLocaleMessage()` inside a `router.beforeEach` guard to avoid shipping all translations upfront. Always set `fallbackLocale` so missing keys degrade gracefully rather than rendering raw key paths.$escape$,
  $escape$// main.ts
import { createI18n } from 'vue-i18n'

const i18n = createI18n({
  legacy: false,
  locale: 'en',
  fallbackLocale: 'en',
  numberFormats: {
    en: { currency: { style: 'currency', currency: 'USD' } },
  },
  messages: { en: { nav: { home: 'Home' } } },
})

// Component.vue <script setup>
import { useI18n } from 'vue-i18n'
const { t, n, locale } = useI18n()
// t('nav.home') → 'Home'
// n(1234.5, 'currency') → '$1,234.50'$escape$,
  $escape$typescript$escape$,
