INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a68a739e-23cc-4324-a732-715690faf275',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vue Memory Leaks — Cleaning Up with onUnmounted and AbortController$escape$,
  $escape$Vue's Composition API gives you onUnmounted to tear down side effects before a component leaves the DOM. Skip it and you'll leak event listeners, intervals, and pending fetch requests every time a component mounts. Every addEventListener needs a paired removeEventListener inside onUnmounted. Timers from setInterval must be cleared. Fetch calls need an AbortController whose signal you pass to fetch — abort it on unmount so stale responses don't update state on an already-destroyed component.

In the Options API, the equivalent hook is beforeDestroy (Vue 2) or beforeUnmount (Vue 3). The Composition API's onUnmounted fires after the component is torn down, so prefer beforeUnmount when you need the DOM still accessible.

watchEffect auto-tracks its dependencies and returns a stop handle, but if you register side effects inside it manually — event listeners, subscriptions — you still own cleanup via its implicit onCleanup callback argument. Vue won't do it for you. The pattern: register in setup, tear down in onUnmounted or onCleanup. No exceptions.$escape$,
  $escape$import { onMounted, onUnmounted, ref } from 'vue'

const data = ref(null)
let controller: AbortController

onMounted(async () => {
  controller = new AbortController()
  try {
    const res = await fetch('/api/feed', { signal: controller.signal })
    data.value = await res.json()
  } catch (e) {
    if ((e as Error).name !== 'AbortError') throw e
  }
})

onUnmounted(() => {
  controller.abort()
})$escape$,
  $escape$typescript$escape$,
