INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9f1e9f41-37b2-47f3-a18d-e4f098c9f7ec',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vue Config Done Right — Validate Env Vars at Startup with Zod$escape$,
  $escape$Vite exposes environment variables to Vue apps via `import.meta.env`, but only variables prefixed with `VITE_` are bundled into the client. Hardcoding API base URLs or keys directly in your composables or `main.ts` is a silent footgun — different environments, broken builds, no feedback until runtime.

Instead, create a `src/env.ts` module that parses and validates all required env vars using Zod at module load time. Import this module at the top of `main.ts` so the app fails fast with a descriptive error before mounting the Vue app tree. This prevents a misconfigured staging deploy from silently hitting production endpoints.

Expose the validated config as a plain typed object. Composables and services import from `env.ts`, never from `import.meta.env` directly. This single indirection gives you type safety, early failure, and a single place to audit every external dependency your Vue app touches. Pair with `.env.example` committed to the repo so new contributors know exactly which vars are required.$escape$,
  $escape$// src/env.ts
import { z } from 'zod'

const schema = z.object({
  VITE_API_BASE_URL: z.string().url(),
  VITE_SENTRY_DSN: z.string().min(1),
  VITE_FEATURE_FLAGS_KEY: z.string().optional(),
})

const parsed = schema.safeParse(import.meta.env)

if (!parsed.success) {
  console.error('Invalid env config:', parsed.error.format())
  throw new Error('App startup aborted: missing or invalid environment variables.')
}

export const env = parsed.data$escape$,
  $escape$typescript$escape$,
